    const leftInc = new Array(n).fill(0);
    const rightInc = new Array(n).fill(0);

    // Fill leftInc: leftInc[i] is the largest j <= i where nums[j..i] is strictly increasing
    leftInc[0] = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1];
        } else {
            leftInc[i] = i;
        }
    }

    // Fill rightInc: rightInc[i] is the smallest j >= i where nums[i..j] is strictly increasing
    rightInc[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1];
        } else {
            rightInc[i] = i;
        }
    }

    // Precompute left decreasing and right decreasing sequences
    const leftDec = new Array(n).fill(0);
    const rightDec = new Array(n).fill(0);

    // Fill leftDec: leftDec[i] is the largest j <= i where nums[j..i] is strictly decreasing
    leftDec[0] = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] < nums[i - 1]) {
            leftDec[i] = leftDec[i - 1];
        } else {
            leftDec[i] = i;
        }
    }

    // Fill rightDec: rightDec[i] is the smallest j >= i where nums[i..j] is strictly decreasing
    rightDec[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            rightDec[i] = rightDec[i + 1];
        } else {
            rightDec[i] = i;
        }
    }

    // Iterate all possible p and q to find valid l and r
    for (let p = 1; p < n - 2; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check if nums[l..p] is strictly increasing, nums[p..q] is strictly decreasing, nums[q..r] is strictly increasing
            const l = leftInc[p];
            const r = rightInc[q];
            const decStart = rightDec[p];
            const decEnd = leftDec[q];

            if (decStart >= q && decEnd <= p) {
                const sum = prefix[r + 1] - prefix[l];
                if (sum > maxSum) {
                    maxSum = sum;
                }
            }
        }
    }

    return maxSum;
}

